'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Plus, MapPin, Users, BookOpen, Calendar, ChevronRight } from 'lucide-react';
import { getAllOrganizations, getAllSessions } from '@/lib/db';
import type { Organization, Session, SessionStatus } from '@/types';

function formatDatetime(datetime: string): string {
  if (!datetime) return '日時未設定';
  const d = new Date(datetime);
  return new Intl.DateTimeFormat('ja-JP', {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  }).format(d);
}

const STATUS_CONFIG: Record<SessionStatus, { label: string; className: string; dot?: boolean }> = {
  draft: {
    label: '下書き',
    className: 'bg-zinc-800 text-zinc-400 border border-zinc-700',
  },
  active: {
    label: '進行中',
    className: 'bg-emerald-950 text-emerald-400 border border-emerald-800',
    dot: true,
  },
  completed: {
    label: '完了',
    className: 'bg-blue-950 text-blue-400 border border-blue-800',
  },
};

function StatusBadge({ status }: { status: SessionStatus }) {
  const cfg = STATUS_CONFIG[status];
  return (
    <span className={`inline-flex items-center gap-1.5 rounded-full px-2.5 py-0.5 text-xs font-medium ${cfg.className}`}>
      {cfg.dot && (
        <span className="relative flex h-1.5 w-1.5">
          <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-emerald-400 opacity-75" />
          <span className="relative inline-flex h-1.5 w-1.5 rounded-full bg-emerald-400" />
        </span>
      )}
      {cfg.label}
    </span>
  );
}

export default function HomePage() {
  const router = useRouter();
  const [organization, setOrganization] = useState<Organization | null>(null);
  const [sessions, setSessions] = useState<Session[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function load() {
      try {
        const [orgs, sess] = await Promise.all([getAllOrganizations(), getAllSessions()]);
        setOrganization(orgs[0] ?? null);
        const sorted = [...sess].sort(
          (a, b) => new Date(b.datetime).getTime() - new Date(a.datetime).getTime()
        );
        setSessions(sorted);
      } finally {
        setLoading(false);
      }
    }
    load();
  }, []);

  function handleSessionClick(session: Session) {
    if (session.status === 'active') {
      router.push(`/record/${session.id}`);
    } else {
      router.push(`/output/${session.id}`);
    }
  }

  return (
    <div className="min-h-screen bg-[#0f0f0f] text-white">
      <div className="mx-auto max-w-3xl px-4 py-10 sm:px-6">

        {/* Header */}
        <header className="mb-10">
          {loading ? (
            <div className="space-y-2">
              <div className="h-8 w-48 animate-pulse rounded-md bg-zinc-800" />
              <div className="h-4 w-32 animate-pulse rounded-md bg-zinc-800" />
            </div>
          ) : (
            <>
              <h1 className="text-3xl font-bold tracking-tight text-white">
                {organization?.name ?? '組織名未設定'}
              </h1>
              {organization?.groupName && (
                <p className="mt-1 text-sm text-zinc-400">{organization.groupName}</p>
              )}
            </>
          )}
        </header>

        {/* New session card */}
        <button
          onClick={() => router.push('/setup')}
          className="group mb-8 flex w-full items-center gap-4 rounded-2xl border border-dashed border-zinc-700 bg-zinc-900/50 p-5 text-left transition-all duration-200 hover:border-zinc-500 hover:bg-zinc-900"
        >
          <span className="flex h-10 w-10 shrink-0 items-center justify-center rounded-full bg-white text-black transition-transform duration-200 group-hover:scale-105">
            <Plus className="h-5 w-5" />
          </span>
          <div>
            <p className="text-sm font-semibold text-white">新しい会議セッションを作成</p>
            <p className="text-xs text-zinc-500 mt-0.5">メンバー・議題を設定して会議を開始</p>
          </div>
          <ChevronRight className="ml-auto h-4 w-4 text-zinc-600 transition-colors group-hover:text-zinc-400" />
        </button>

        {/* Session list */}
        <section>
          <h2 className="mb-4 text-xs font-semibold uppercase tracking-widest text-zinc-500">
            過去のセッション
          </h2>

          {loading ? (
            <div className="space-y-3">
              {[...Array(3)].map((_, i) => (
                <div key={i} className="h-24 animate-pulse rounded-xl bg-zinc-800/50" />
              ))}
            </div>
          ) : sessions.length === 0 ? (
            <div className="rounded-xl border border-zinc-800 bg-zinc-900/30 px-6 py-10 text-center">
              <p className="text-sm text-zinc-500">セッションがまだありません</p>
            </div>
          ) : (
            <ul className="space-y-2">
              {sessions.map((session) => (
                <li key={session.id}>
                  <button
                    onClick={() => handleSessionClick(session)}
                    className="group w-full rounded-xl border border-zinc-800 bg-zinc-900/40 p-4 text-left transition-all duration-150 hover:border-zinc-700 hover:bg-zinc-900"
                  >
                    <div className="flex items-start justify-between gap-3">
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center gap-2">
                          <p className="truncate text-sm font-semibold text-white">
                            {session.title || '無題のセッション'}
                          </p>
                          <StatusBadge status={session.status} />
                        </div>

                        <div className="mt-2 flex flex-wrap items-center gap-x-4 gap-y-1">
                          <span className="flex items-center gap-1 text-xs text-zinc-500">
                            <Calendar className="h-3 w-3 shrink-0" />
                            {formatDatetime(session.datetime)}
                          </span>
                          {session.location && (
                            <span className="flex items-center gap-1 text-xs text-zinc-500">
                              <MapPin className="h-3 w-3 shrink-0" />
                              {session.location}
                            </span>
                          )}
                          <span className="flex items-center gap-1 text-xs text-zinc-500">
                            <Users className="h-3 w-3 shrink-0" />
                            {session.members.length}名
                          </span>
                          <span className="flex items-center gap-1 text-xs text-zinc-500">
                            <BookOpen className="h-3 w-3 shrink-0" />
                            {session.agendas.length}議題
                          </span>
                        </div>
                      </div>
                      <ChevronRight className="mt-0.5 h-4 w-4 shrink-0 text-zinc-700 transition-colors group-hover:text-zinc-500" />
                    </div>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </section>
      </div>
    </div>
  );
}
